class Solution {
public:
    int possibleStringCount(string word, int k) {
        int n = word.size();
        int res = 0;
        for (int i = k; i <= n; i++) {
            int count[26] = {0};
            for (int j = 0; j < i; j++) {
                count[word[j] - 'a']++;
            }
            long long temp = 1;
            for (int j = 0; j < 26; j++) {
                temp = (temp * (count[j] + 1)) % (1e9 + 7);
            }
            res = (res + temp) % (1e9 + 7);
        }
        return res;
    }
};
